/* Enhanced Publication Cards with Modern Design */
.publication-card {
  background: var(--bg-primary, var(--bs-body-bg));
  padding: 2rem;
  border-radius: 16px;
  border: 1px solid var(--border-light, var(--bs-border-color));
  box-shadow: 0 4px 20px var(--shadow-light, rgba(0,0,0,0.1));
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  margin-bottom: 2rem;
}

.publication-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 40px var(--shadow-medium, rgba(0,0,0,0.15));
  border-color: var(--primary-color, var(--bs-primary));
}

.publication-card.featured {
  border-color: var(--primary-color, var(--bs-primary));
  box-shadow: 0 4px 20px var(--shadow-primary, rgba(37, 99, 235, 0.15));
}

.publication-card.featured::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg, var(--primary-color, var(--bs-primary)), var(--primary-light, var(--bs-primary-bg)));
}

.publication-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1.5rem;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.publication-badge {
  display: inline-block;
  padding: 0.4rem 1rem;
  border-radius: 20px;
  font-size: 0.85rem;
  font-weight: 600;
  margin-right: 0.5rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.publication-badge.featured {
  background: linear-gradient(135deg, #ffc107, #ff8c00);
  color: #000;
}

.publication-badge.published {
  background: linear-gradient(135deg, #16a34a, #15803d);
  color: white;
}

.publication-badge.under-review {
  background: linear-gradient(135deg, #dc2626, #b91c1c);
  color: white;
}

.publication-badge.in-preparation {
  background: linear-gradient(135deg, #9333ea, #7c3aed);
  color: white;
}

.publication-badge.presented {
  background: linear-gradient(135deg, #059669, #047857);
  color: white;
}

.publication-year {
  background: linear-gradient(135deg, var(--primary-color, var(--bs-primary)), var(--primary-dark, var(--bs-primary)));
  color: white;
  padding: 0.4rem 1rem;
  border-radius: 20px;
  font-size: 0.9rem;
  font-weight: 600;
  letter-spacing: 0.05em;
}

.publication-citation {
  font-size: 1rem;
  line-height: 1.6;
  margin-bottom: 1.5rem;
  text-align: justify;
  color: var(--text-primary, var(--bs-body-color));
}

.publication-tags {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.publication-tags li {
  background: var(--primary-subtle, var(--bs-primary-bg));
  color: var(--primary-color, var(--bs-primary));
  padding: 0.3rem 0.8rem;
  border-radius: 12px;
  font-size: 0.85rem;
  font-weight: 500;
  border: 1px solid rgba(37, 99, 235, 0.2);
  transition: all 0.2s ease;
}

.publication-tags li:hover {
  background: var(--primary-color, var(--bs-primary));
  color: white;
  transform: translateY(-1px);
}

/* Publications Section Layout */
.publications-section {
  margin-bottom: 4rem;
}

.publications-section h3 {
  font-size: 2rem;
  font-weight: 700;
  color: var(--text-primary, var(--bs-body-color));
  margin-bottom: 2rem;
}

/* Publication Filters */
.publication-filters {
  margin-bottom: 3rem;
  padding: 2rem;
  background: var(--bs-secondary-bg);
  border-radius: 16px;
  border: 1px solid var(--bs-border-color);
}

.filter-group {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.filter-group:last-child {
  margin-bottom: 0;
}

.filter-btn {
  background: white;
  border: 2px solid var(--bs-border-color);
  color: var(--bs-body-color);
  padding: 0.75rem 1.5rem;
  border-radius: 25px;
  font-weight: 600;
  font-size: 0.9rem;
  cursor: pointer;
  transition: all 0.3s ease;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.filter-btn:hover {
  background: var(--bs-primary);
  border-color: var(--bs-primary);
  color: white;
  transform: translateY(-2px);
  box-shadow: 0 4px 15px rgba(37, 99, 235, 0.3);
}

.filter-btn.active {
  background: linear-gradient(135deg, var(--bs-primary), var(--bs-primary-dark, #1e40af));
  border-color: var(--bs-primary);
  color: white;
  box-shadow: 0 4px 15px rgba(37, 99, 235, 0.4);
}

.publications-container {
  position: relative;
}

.publication-item {
  transition: all 0.5s ease;
  opacity: 1;
  transform: scale(1);
  margin-bottom: 2rem;
}

.publication-item.hidden {
  opacity: 0;
  transform: scale(0.8);
  height: 0;
  margin: 0;
  overflow: hidden;
}

/* Animation for filter transitions */
.publication-item.filtering-out {
  animation: fadeOut 0.3s ease forwards;
}

.publication-item.filtering-in {
  animation: fadeIn 0.3s ease forwards;
}

@keyframes fadeOut {
  to {
    opacity: 0;
    transform: scale(0.8);
    height: 0;
    margin: 0;
  }
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: scale(0.8);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

/* Filter result counter */
.filter-results {
  text-align: center;
  padding: 1rem;
  color: var(--bs-secondary);
  font-style: italic;
}

/* Responsive Design */
@media (max-width: 768px) {
  .publication-card {
    padding: 1.5rem;
    margin-bottom: 1.5rem;
  }

  .publication-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 1rem;
  }

  .publication-badge,
  .publication-year {
    font-size: 0.8rem;
    padding: 0.3rem 0.8rem;
  }

  .publication-filters {
    padding: 1.5rem;
    margin-bottom: 2rem;
  }

  .filter-btn {
    padding: 0.6rem 1.2rem;
    font-size: 0.8rem;
  }

  .filter-group {
    gap: 0.5rem;
  }
}
</style>
